const TEXT_PATH = 'body.fields.description'; // e.g. 'body.fields.description'

const ALLOWED_LANGUAGES = [
  'Croatian','Czech','Danish','Dutch','Estonian','Filipino','Finnish','French','German','Greek',
  'Hungarian','Indonesian','Italian','Korean','Latvian','Lithuanian','Malay','Norwegian','Polish',
  'Portuguese (Brazil)','Romanian','Slovak','Slovenian','Spanish','Swedish','Thai','Turkish',
  'Ukrainian','Vietnamese',
];

const normalize = (s) => String(s).trim().toLowerCase();
const allowedLookup = new Map(ALLOWED_LANGUAGES.map((l) => [normalize(l), l]));

/**
 * Safely read nested values from an object using a dot path, e.g. "body.fields.description".
 * Supports numeric segments like "arr.0.name".
 */
function getByPath(obj, path, defaultValue = '') {
  if (!obj || !path) return defaultValue;

  const parts = String(path)
    .split('.')
    .map(p => p.trim())
    .filter(Boolean);

  let cur = obj;
  for (const part of parts) {
    if (cur == null) return defaultValue;

    const key = /^[0-9]+$/.test(part) ? Number(part) : part;
    if (typeof cur === 'object' && key in cur) {
      cur = cur[key];
    } else {
      return defaultValue;
    }
  }
  return cur ?? defaultValue;
}

// Extract languages only from the "Target languages:" line (label is case-insensitive)
function extractTargetLanguagesLine(text) {
  if (!text) return '';
  const str = String(text);
  const match = str.match(/target\s*languages\s*:\s*(.*)$/im);
  return match ? match[1] : '';
}

function parseLanguagesFromLine(line) {
  if (!line) return [];

  const parts = line
    .split(',')
    .map((p) => p.trim())
    .filter(Boolean);

  const seen = new Set(); // normalized canonical keys for dedupe
  for (const p of parts) {
    const canonical = allowedLookup.get(normalize(p)); // full match only
    if (canonical) seen.add(normalize(canonical));
  }

  // Order not important
  return Array.from(seen).map((k) => ({ value: allowedLookup.get(k) }));
}

return items.map((item) => {
  const text = getByPath(item.json, TEXT_PATH, '');

  const langLine = extractTargetLanguagesLine(text);
  const languages = parseLanguagesFromLine(langLine);

  return {
    json: {
      languages,
    },
  };
});

